#include <bits/stdc++.h>
using namespace std;
int main()
{
    int a,c=0,d=0;
    cin>>a;
    int b[a];
    for(int i=0;i<a;i++)
        {
            cin>>b[i];
            c++;
            d=0;
            for(int i=0;i<c;i++)
                {
                    if(b[i]<b[c-1])
                    {
                        d++;
                    }
                }
            cout<<d<<" ";
        }
    return 0;
}
